Answer:
int count_unique(int array[], int n) 
{ 
    int count = 0; 
    int visited[n]; 
    for (int i = 0; i < n; i++) 
        visited[i] = 0; 

    for (int i = 0; i < n; i++) { 
        if (!visited[i]) { 
            visited[i] = 1; 
            count++; 
            for (int j = i + 1; j < n; j++) 
                if (array[i] == array[j]) 
                    visited[j] = 1; 
        } 
    } 
    return count; 
}

