def subset(arr, K): 
    n = len(arr) 
    subset_arr = [0]; 

    for i in range (0, n): 
        x = len(subset_arr) 
        for j in range(0, x): 

            # Generate subset by adding 
            # elements of A
            temp = [] 
            temp = subset_arr[j] 
            temp.append(arr[i]) 

            # Append in the list 
            subset_arr.append(temp) 

    # Return K size subset 
    length = len(subset_arr) 
    if (length >= K): 
        return subset_arr[length - K:] 
    else: 
        return -1

