def get_all_permutations(string):

  if len(string) == 1:
    return [string]

  permutations = []
  for index, char in enumerate(string):
    slice_string  = string[:index] + string[index+1:]
    for permutation in get_all_permutations(slice_string):
      permutations.append(char + permutation)

  return permutations

