def min_difference(arr):
  min_diff = abs(arr[1] - arr[0])
  for i in range(1, len(arr)-1):
    diff = abs(arr[i+1] - arr[i])
    if diff < min_diff:
      min_diff = diff
  return min_diff

def find_missing(arr):
  # sort the array
  arr.sort()

  # iterate through the array 
  # to find the smallest positive integer not present 
  for i in range(len(arr)):
    if arr[i] > 0:
      if arr[i+1] != arr[i] + 1:
        return arr[i] + 1
  return arr[-1] + 1

def binary_search(arr, target):
  low = 0
  high = len(arr) - 1

  while low <= high: 
    mid = (low + high) // 2
    if arr[mid] == target: 
      return mid 
    elif arr[mid] < target: 
      low = mid + 1
    else: 
      high = mid - 1
  return -1

