def binary_search(arr, num, start, end): 
    if start >= end: 
        return None

    mid = start + (end - start)//2
    if arr[mid] == num: 
        return mid 

    if arr[mid] < num: 
        return binary_search(arr, num, mid+1, end) 
    else: 
        return binary_search(arr, num, start, mid-1)

