// initialise slow and fast pointers 
let slow = head;
let fast = head;

while (fast !== null && fast.next !== null) {  
  fast = fast.next.next;  
  if(slow === fast) { 
    break;
  }  
  slow = slow.next;  
} 

// check if there is a cycle  
if (slow === null || fast === null || fast.next === null) { 
  return;
}  
// initialize slow pointer to head  
slow = head;  
while (slow !== fast) {  
  slow = slow.next;  
  fast = fast.next;  
} 

// assign the cycle end  
fast.next = slow;

