def anagram_checker(str1, str2):
    if len(str1) != len(str2):
        return False
    else:
        char_list1 = [0] * 26
        for char in str1:
            char_list1[ord(char)-97] += 1
        for char in str2:
            if char_list1[ord(char)-97] == 0:
                return False
            char_list1[ord(char)-97] -= 1
        return True

