def rotate_matrix(matrix):
    m = len(matrix)
    # Create a new matrix
    new_matrix = [[0 for _ in range(m)] for _ in range(m)]
    # Rotate the matrix
    for i in range(m):
        for j in range(m): 
            new_matrix[j][m - i - 1] = matrix[i][j]
    # Return the rotated matrix
    return new_matrix

