def permutation(str): 
    if len(str) == 0: 
        return [] 
    if len(str) == 1: 
        return [str]  
    l = []  
    for i in range(len(str)): 
       m = str[i]  
       remLst = str[:i] + str[i+1:]  
       for p in permutation(remLst): 
           l.append([m] + p) 
    return l 

