class node:
    def __init__(self, data):
        self. data = data
        self. next = None

def removeGreater(head, value):
    while head and head.data > value:
        head = head.next
    p = head
    while p and p.next:
        if p.next.data > value:
            p.next = p.next.next
        else:
            p = p.next
    return head

