# A node  
class Node:  
    def __init__(self,key): 
        self.left = None
        self.right = None
        self.val = key 

# A function to insert a new node with the given key  
def insert(root,node): 
    if root is None: 
        root = node 
    else: 
        if root.val < node.val: 
            if root.right is None: 
                root.right = node 
            else: 
                insert(root.right, node) 
        else: 
            if root.left is None: 
                root.left = node 
            else: 
                insert(root.left, node) 

