// Function to add two numbers using unary operator 
int addNumbers(int x, int y) 
{ 
    // Iterate till there is no carry 
    while (y != 0) 
    { 
        // carry now contains common 
        // set bits of x and y 
        int carry = x & y; 

        // Sum of bits of x and y where at 
        // least one of the bits is not set 
        x = x ^ y; 

        // Carry is shifted by one so that  
        // adding it to x gives the required sum 
        y = carry << 1; 
    } 
    return x; 
}

// Recursive function to find the maximum depth 
// of a binary tree 
int maxDepth(Node *root) 
{ 
    // Base case 
    if (root == NULL) 
        return 0; 

    // Recur for left subtree and right subtree 
    int lDepth = maxDepth(root->left); 
    int rDepth = maxDepth(root->right); 

    // Use the larger one 
    if (lDepth > rDepth) 
        return lDepth + 1; 
    else
        return rDepth + 1; 
}

// Function to calculate the checksum of a given string 
// *str is the given string 
long calculateChecksum(string str) 
{ 
	long checksum = 0; 

	for (int i = 0; i < str.length(); i++) { 
		checksum += str.at(i); 
	} 
	return checksum; 
} 
