def binary_search(list, target):
 low = 0
 high = len(list) - 1

 while low <= high:
  mid = (low + high) // 2
  if list[mid] < target:
   low = mid + 1
  elif list[mid] > target:
   high = mid - 1
  else:
   return mid
 return False

