def sorting_algorithm(sort_me):
    len_sortme = len(sort_me)
    for i in range(len_sortme):
        for j in range(0, len_sortme-i-1):
            if sort_me[j] > sort_me[j+1]:
                sort_me[j], sort_me[j+1] = sort_me[j+1], sort_me[j]
    return sort_me

