def findSumPairs(v, sum):  
    v.sort()
    l = 0
    r = len(v) - 1
    while l < r: 
        if v[l] + v[r] == sum:
            return True
        elif v[l] + v[r] > sum:
            r -= 1
        else:
            l += 1
    return False

