def max_subarray_sum(arr):
    max_sum = 0
    curr_sum = 0
    for x in arr:
        curr_sum += x
        if curr_sum < 0:
            curr_sum = 0
        elif curr_sum > max_sum:
            max_sum = curr_sum
    return max_sum

