def most_frequent_char(s):
    count = [0] * 256
    max_count = 0
    max_id = 0
    for i in range(len(s)):
        count[ord(s[i])] += 1
        if count[ord(s[i])] > max_count:
            max_count = count[ord(s[i])]
            max_id = i

    return s[max_id]

