#include <stdio.h> 

int main() 
{ 
    int n, first = 0, second = 1, next; 

    printf("Enter the number of terms \n"); 
    scanf("%d", &n); 

    printf("First %d terms of Fibonacci series are :\n", n); 

    int i; 
    for (i = 0; i < n; i++) { 
        if (i <= 1) 
            next = i; 
        else { 
            next = first + second; 
            first = second; 
            second = next; 
        } 
        printf("%d\n", next); 
    } 

    return 0; 
}

