void reverse_string(char *str) {
    int len = strlen(str);
    int i;
    char *rev_str = (char*)malloc((len+1)*sizeof(char));
    for(i = 0; i < len; i++) {
        rev_str[i] = str[len - i - 1];
    }
    rev_str[len] = '\0';
    printf("Reversed string: %s\n", rev_str);
    free(rev_str);
}

