function mostFrequent(arr) {
    let maxCount = 0;
    let item;
    let frequencyMap = new Map();

    arr.forEach(name => {
        if (frequencyMap.has(name)) {
            frequencyMap.set(name, frequencyMap.get(name) + 1);
        } else {
            frequencyMap.set(name, 1);
        }
    });

    for (let [name, count] of frequencyMap.entries()) {
        if (count > maxCount) {
            maxCount = count;
            item = name;
        }
    }

    return item;
}

