def is_sorted(arr, order = "asc"):
    #check if array is sorted in ascending or descending order
    if order == "asc":
        for i in range(0, len(arr)-1):
            if arr[i] > arr[i+1]:
                return False
    elif order == "desc":
        for i in range(0, len(arr)-1):
            if arr[i] < arr[i+1]:
                return False
    else:
        print("Error: Invalid sort order!")
