# Find First Non-Repeating Character
def first_non_repeat(string): 
    seen = {} 

    for char in string: 
        if char not in seen: 
            seen[char] = 0 
        seen[char] += 1

    # Find the first character that appears once
    for i in range(len(string)): 
        if seen[string[i]] == 1: 
            return string[i] 

    return '_'


