def selection_sort(arr):
    for i in range(len(arr),1,-1):
        max_element=arr[0]
        for j in range(i):
            if arr[j] > max_element :
                max_element=arr[j]

        temp = arr[i-1]
        arr[i-1] = max_element
        arr[arr.index(max_element)] = temp

