def permutations(list): 
    if len(list) == 0: 
        return [] 
    if len(list) == 1: 
        return [list]
    l = [] #empty list 

    for i in range(len(list)): 
        m = list[i] 
        remList = list[:i] + list[i+1:] 
        for p in permutations(remList): 
            l.append([m] + p) 
    return l

