def tree_str(root):
    if root is None:
        return ''

    left_str = tree_str(root.left)
    right_str = tree_str(root.right)

    if left_str != '' and right_str != '':
        return '(' + left_str + ')' + str(root.val) + '(' + right_str + ')'
    if left_str != '' and right_str == '':
        return '(' + left_str + ')' + str(root.val)
    if left_str == '' and right_str != '':
        return  str(root.val) + '(' + right_str + ')'
    else:
        return str(root.val)

