using namespace std;

stack<int> reverseStack(stack<int> s) {
    stack<int> tempStack;
    while (!s.empty()) {
        int temp = s.top();
        tempStack.push(temp);
        s.pop();
    }
    return tempStack;
}

int main() {
    stack<int> s;
    s.push(1); s.push(2);
    s.push(3); s.push(4);
    s.push(5);

    stack<int> revStack = reverseStack(s);
    while (!revStack.empty()) {
        cout << revStack.top() << " ";
        revStack.pop();
    }
    return 0;
}

