def roman_to_integer(numeral):
  romans = {"I": 1,
            "V": 5,
            "X": 10,
            "L": 50,
            "C": 100,
            "D": 500,
            "M": 1000
            }
  num = 0
  i = 0
  while i < len(numeral):
    if i+1 < len(numeral):
      if romans[numeral[i]] >= romans[numeral[i+1]]:
        num = num + romans[numeral[i]]
      else :
        num = num + romans[numeral[i+1]] - romans[numeral[i]]
        i+=1
    else:
      num = num + romans[numeral[i]]
    i+=1
  return num

