const permute = str => {
  let results = [];

  const permutations = (subStr, rest) => {
    if (!rest.length) {
      results.push(subStr);
    } else {
      for (let i = 0; i < rest.length; i++) {
        let newSubStr = subStr + rest[i];
        let newRest = rest.substring(0, i) + rest.substring(i + 1);
        permutations(newSubStr, newRest);
      }
    }
  }

  permutations('', str);
  return results;
}

