def quick_sort(arr):
  if len(arr) <= 1:
    return arr
  else:
    pivot = arr[0]
    left, right = [], []
    # pivot
    for x in arr[1:]:
      if x > pivot:
        right.append(x)
      else:
        left.append(x)
    # concatenate
    return quick_sort(left) + [pivot] + quick_sort(right)

