def longest_substring_without_repeating_characters(str):
    start, max_len = 0, 0
    used_char = {}

    for i, char in enumerate(str):
        if char in used_char and start <= used_char[char]:
            start = used_char[char] + 1
        else:
            max_len = max(max_len, i - start + 1)

        used_char[char] = i

    return max_len

