def permute(s): 
    if len(s) == 0: 
        return [''] 
    prev_permutation_list = permute(s[1:len(s)])  
    next_list = [] 
    for p in prev_permutation_list: 
        for j in range(len(p) + 1): 
            next_list.append(p[0:j] + s[0] + p[j:len(p)])  
    return next_list

