def FibonacciSum(n): 
    fib1 = 0
    fib2 = 1
    if n < 0: 
        return "Incorrect input"
    elif n == 0:
        return 0
    elif n == 1: 
        return 0
    else: 
        sum = 0
        for i in range(2,n+1): 
            fib_n = fib1 + fib2
            fib1 = fib2
            fib2 = fib_n
            sum = sum + fib_n
        return sum

