from math import sqrt

def prime_numbers(n):
    primes = []
    i = 2
    while len(primes) < n:
        for number in range(2, int(sqrt(i)) + 1):
            if i % number == 0:
                break
        else:
            primes.append(i)
        i += 1
    yield from primes

