def union(A, B):
    union_set = set()
    for item in A:        
        union_set.add(item)

    for item in B:
        union_set.add(item)
    return union_set

def nth_prime(n):
    if n == 0:
        return None

    primeCount = 0
    checkNum = 2
    while(primeCount < n):
        isPrime = True
        for i in range(2, checkNum):
            if checkNum % i == 0:
                isPrime = False

        if isPrime == True:
            primeCount += 1

        if primeCount == n:
            return checkNum
        else:
            checkNum += 1

