def most_frequent(data):
    freq = {}
    for x in data:
        if x in freq:
            freq[x] += 1
        else:
            freq[x] = 1
    max_freq = 0
    for x in freq.values():
        if x > max_freq:
            max_freq = x
    most_frequent_item = []
    for x in freq.keys():
        if freq[x] == max_freq:
            most_frequent_item.append(x)
    return most_frequent_item

