public static int ConvertToDecimal (int value, int base) 
{ 
    int decimalValue = 0; 

    int i = 0; 
    while (value != 0 && i++ < 8) 
    { 
        int remainder = value % 10; 
        value /= 10; 

        decimalValue += remainder * (int)Math.Pow(base, i); 
    }
    return decimalValue;
}

