class ArithmeticOperator:
    def __init__(self, operator, left, right):
        self.operator = operator
        self.left = left
        self.right = right

    def operate(self):
        if self.operator == "+":
            return self.left + self.right
        elif self.operator == "-":
            return self.left - self.right
        elif self.operator == "*":
            return self.left * self.right
        elif self.operator == "/":
            return self.left / self.right
        else:
            raise ValueError('Not a valid operator')

