def sortStackAsc(stack):
    sorted_stack = []

    while stack:
        current_element = stack.pop()
        while sorted_stack and current_element < sorted_stack[-1]:
            stack.append(sorted_stack.pop())
        sorted_stack.append(current_element)

    return sorted_stack

