    numbers = [1,4,5,3,6]
    print(optimal_sum(target, numbers))

"""
Use features of the Python language to implement 3-way partitioning of a given array.
"""
def threeWayPartition(array, pivot): 
    less = [] 
    equal = [] 
    greater = [] 
    for i in array: 
        if i < pivot: 
            less.append(i) 
        elif i == pivot: 
            equal.append(i) 
        else: 
            greater.append(i)   
    return less + equal + greater 

