import time

def throttle_messages(limit, window):
    count = 0
    start = time.time()

    while count < limit:
        next_message = yield
        count += 1

        end = time.time()
        if (end - start) > window: 
            count = 0
            start = end

    yield

def fibonacci_generator(n):
    a, b = 0, 1
    while a < 2 * n - 1:
