def contains(value, head):
    current_node = head
    while current_node is not None:
        if current_node.value == value:
            return True
        current_node = current_node.next
    return False

def FindMax(arr):
    curr_max = arr[0]
    curr_index = 0
    for i in range(len(arr)):
        if arr[i] > curr_max:
            curr_max = arr[i]
            curr_index = i
    return curr_max, curr_index

