def FibonacciSeries(n):
    if n <= 0:
        return [0]
    elif n == 1:
        return [0,1]
    else:
        series = [0,1]
        for i in range(2, n):
            curr_num = series[i-1] + series[i-2]
            series.append(curr_num)
        return series

def insert(self,val): 
	if not self.root: 
		self.root = Node(val) 
	else: 
		current = self.root
		while True: 
			if val < current.val: 
				if current.left: 
					current = current.left 
				else: 
					current.left = Node(val) 
					break
			elif val > current.val: 
				if current.right: 
					current = current.right 
				else: 
					current.right = Node(val) 
					break
			else: 
				break

