def countK(arr, k): 
    if len(arr) == 0: 
        return 0
    if arr[0] % k == 0: 
        return 1 + countK(arr[1:], k)
    else: 
        return 0 + countK(arr[1:], k)

def median(data):
    data.sort()
    length = len(data)
    if length == 0:
        return 0
    if length % 2 == 0:
        return (data[length // 2] + data[length // 2 - 1]) / 2
    elif length % 2 == 1:
        return data[length // 2]

