def fill_matrix_zeros(matrix):
    n, m = len(matrix), len(matrix[0])
    col0_zero = False
    for i in range(n):
        if matrix[i][0] == 0:
            col0_zero = True
        for j in range(1, m):
            if matrix[i][j] == 0:
                matrix[i][0] = 0
                matrix[0][j] = 0

    for i in range(1, n):
        for j in range(1, m):
            if matrix[i][0] == 0 or matrix[0][j] == 0:
                matrix[i][j] = 0

    if matrix[0][0] == 0:
        for j in range(m):
            matrix[0][j] = 0

    if col0_zero:
        for i in range(n):
            matrix[i][0] = 0

