def lcs(str1, str2, n, m): 
    if n == 0 or m == 0:          
        return 0

    elif str1[n-1] == str2[m-1]:   
        return 1 + lcs(str1, str2, n-1, m-1) 

    else: 
        return max(lcs(str1, str2, n, m-1),    
                   lcs(str1, str2, n-1, m))

def third_largest(root):
    if root is None:
        return None

    queue = []
    queue.append(root)
    while len(queue):
        curr = queue.pop(0)

        if curr.right:
            queue.append(curr.right)
        if curr.left:
            queue.append(curr.left)

    if len(queue)>1:
        return queue[1].val
