def DFS(root):
    S = []
    visited = []

    S.append(root)

    while len(S) > 0:
        node = S.pop()
        visited.append(node)

        for vertex in node.get_adjacent_vertices():
            if vertex not in visited:
                S.append(vertex)
    return visited

def rot13(message):
    output = []
    for char in message:
        char_code = ord(char)
        if char_code >= ord('A') and char_code <= ord('Z'):
            # Rotate lower case characters
            char_code += 13
            if char_code > ord('Z'):
                char_code -= 26
        elif char_code >= ord('a') and char_code <= ord('z'):
            # Rotate upper case characters
            char_code += 13
            if char_code > ord('z'):
                char_code -= 26
        output.append(chr(char_code))
    return ''.join(output)
print(rot13("Hello World"))

def edit_distance(str1, str2): 
    n1 = len(str1) 
    n2 = len(str2) 

    dp = [[0 for x in range(n2 + 1)] for x in range(n1 + 1)] 

    for i in range(n1 + 1): 
        for j in range(n2 + 1): 
            if i == 0: 
                dp[i][j] = j
            elif j == 0: 
                dp[i][j] = i
            elif str1[i - 1] == str2[j - 1]: 
                dp[i][j] = dp[i - 1][j - 1] 
            else: 
                dp[i][j] = 1 + min(dp[i][j - 1],
                                   dp[i - 1][j],
                                   dp[i - 1][j - 1]) 

    return dp[n1][n2] 

