class Stack:
    def __init__(self):
        self.queue = []

    def push(self, item):
        self.queue.append(item)
        # Reverse the queue to implement a stack
        self.queue.reverse()

    def pop(self):
        if self.queue:
            # Reverse the queue to implement a stack
            self.queue.reverse()
            return self.queue.pop()
        return None

