#Function to check if a number is an Armstrong number
def isArmstrong(number):
   sum  = 0
   temp = number

   while temp > 0:
    digit = temp % 10
    sum += digit ** 3
    temp //= 10

   if number == sum:
       return True
   else:
       return False

