def longest_strings(str_arr):
    longest = 0
    strings = []
    for string in str_arr:
        if len(string) > longest:
            strings = [string]
            longest = len(string)
        elif len(string) == longest:
            strings.append(string)
    return strings

def longest_consecutive_str(s):
    longest_str = ""
    cur_str = ""

    for char in s:
        if not cur_str or char == cur_str[-1]:
            cur_str += char
        else:
            if len(cur_str) > len(longest_str):
                longest_str = cur_str
            cur_str = char

    if len(cur_str) > len(longest_str):
            longest_str = cur_str

    return longest_str

def transpose(matrix):
    tr_matrix = [[None for i in range(len(matrix))] for j in range(len(matrix[0]))]
    for i, row in enumerate(matrix):
        for j, col in enumerate(row):
            tr_matrix[j][i] = col
    return tr_matrix

def filter_by_character(str_arr, char):
    filtered_arr = []
    for string in str_arr:
        if char in string:
            filtered_arr.append(string)
    return filtered_arr

def sorting_algorithm(arr):
    for i in range(len(arr)-1):
        for j in range(i+1, len(arr)):
            if arr[i] > arr[j]:
                arr[i], arr[j] = arr[j], arr[i]
    return arr

