    sorted <- sort(arr)
    n <- length(arr)
    if(n%%2 == 0){
        mid <- n/2
        median <- (sorted[mid] + sorted[mid + 1] ) / 2
    } else {
        mid <- (n + 1) / 2
        median <- sorted[mid]
    }
    return(median)
}

