    if root is None: 
        return

    if (len(path) > pathLen):  
        path[pathLen] = root.data
    else: 
        path.append(root.data) 

    pathLen = pathLen + 1

    if root.left is None and root.right is None: 
        for i in range(pathLen):
            print(path[i],end=" ")
        print() 
    else: 
        print_paths_util(root.left, path, pathLen) 
        print_paths_util(root.right, path, pathLen)

