def most_frequent_word(str): 
    split_str = str.split() 

    frequencies = {} 
    for word in split_str: 
        if word in frequencies: 
            frequencies[word] += 1
        else: 
            frequencies[word] = 1

    most_frequent_word = "" 
    highest_freq = 0
    for key, value in frequencies.items(): 
        if value > highest_freq: 
            highest_freq = value 
            most_frequent_word = key 

    return most_frequent_word 

