def find_median(A, B):
    """Function to find median of two sorted arrays"""
    m = len(A)
    n = len(B)
    if m > n:
        A,B,m,n = B,A,n,m
    imin, imax, half_len = 0, m , (m+n+1) // 2
    while imin <= imax:
        i = (imin+imax) // 2
        j = half_len -i
        if i < m and B[j-1] > A[i]:
            # i is too small, must increase it
            imin = i + 1
        elif i > 0 and A[i-1] > B[j]:
            # i is too big, must decrease it
            imax = i - 1
        else:
            # i is perfect
            if i == 0:
                max_of_left = B[j-1] 
            elif j == 0:
                max_of_left = A[i-1] 
            else:
                max_of_left = max(A[i-1], B[j-1]) 

            if (m + n) % 2 == 1:
                return max_of_left 

            if i == m:
                min_of_right = B[j] 
            elif j == n:
                min_of_right = A[i] 
            else:
                min_of_right = min(A[i], B[j]) 

            return (max_of_left + min_of_right) / 2.0

if __name__ == '__main__':
    A = [1,4,6,7]
    B = [3,5,8,9]
    median = find_median(A, B)
    print(median)

def get_alphabet_frequencies(sentence):
    """Function to generate a dictionary that contains the frequencies of all English alphabets in a given sentence"""
    alphabet_freq = dict()
    for el in sentence:
        if el.isalpha():
            el = el.lower()
            if el in alphabet_freq:
                alphabet_freq[el] += 1
            else:
                alphabet_freq[el] = 1
    return alphabet_freq

