def most_common(arr):
    freq = {}

    # Count the frequency of each element
    for el in arr:
        if el not in freq:
            freq[el] = 1
        else:
            freq[el] += 1

    # Find the maximum frequency
    max_freq = -1
    for el, freq in freq.items():
        max_freq = max(max_freq, freq)

    # Find the element with maximum frequency
    most_common_el = None
    for el, freq in freq.items():
        if freq == max_freq:
            most_common_el = el

    return most_common_el

