def find_largest_sum(arr):
  max_sum = 0
  first_ele = arr[0]
  sec_ele = arr[1]

  for i in range(0, len(arr)):
    for j in range(i+1, len(arr)):
      curr_sum = arr[i] + arr[j]
      if curr_sum > max_sum:
        max_sum = curr_sum
        first_ele = arr[i]
        sec_ele = arr[j]
  return [first_ele, sec_ele]

