def compute_avg(numbers):
    total = 0
    for num in numbers:
        total += num
    return total/len(numbers)

def compute_sum(root):
    if not root:
        return 0
    left_sum = compute_sum(root.left)
    right_sum = compute_sum(root.right)
    return root.val + left_sum + right_sum

