def longest_increasing_subsequence_length(nums):
    n = len(nums)
    LIS = [1] * n

    for i in range(1, n):
        for j in range(0, i):
            if nums[i] > nums[j] and LIS[i] < LIS[j] + 1:
                LIS[i] = LIS[j] + 1

    return max(LIS)

function countMatchingChar(str1: string, str2: string): number {
    let count = 0;
    if(str1.length != str2.length) {
        return -1; // handle unequal lengths
    }
    for(let i = 0; i < str1.length; i++) {
        if(str1.charAt(i) === str2.charAt(i)) {
            count++;
        }
    }
    return count;
}

