function combineArray(arr1, arr2) {
    let combined = [];

    let l = 0;
    let r = 0;

    while ((l < arr1.length) && (r < arr2.length)) {
        if (arr1[l] < arr2[r]) {
            combined.push(arr1[l]);
            l++;
        } else {
            combined.push(arr2[r]);
            r++;
        }
    }

    while (l < arr1.length) {
        combined.push(arr1[l]);
        l++;
    }

    while (r < arr2.length) {
        combined.push(arr2[r]);
        r++;
    }
    return combined;
}

