def edit_strings(s1, s2):
    s1_arr = list(s1)
    s2_arr = list(s2)

    i = 0
    while i < len(s1):
        if s1[i] == s2[i]:
            i += 1
        else:
            # remove character
            del s1_arr[i]
            if s1_arr == s2_arr:
                return 'removal'
            # insert character
            s1_arr.insert(i, s2[i])
            if s1_arr == s2_arr:
                return 'insertion'
            # replace character
            s1_arr[i] = s2[i]
            if s1_arr == s2_arr:
                return 'replacement'
            break
    return None

