const IDLE = 'IDLE';
const COIN_INPUT = 'COIN_INPUT';
const SELECTION = 'SELECTION';
const DISPENSE = 'DISPENSE';

// Transitions
const transitions = {
    [IDLE]: [COIN_INPUT],
    [COIN_INPUT]: [SELECTION],
    [SELECTION]: [DISPENSE],
    [DISPENSE]: [IDLE]
};

