"""
Function rotate array to the right by k steps
"""

const rotateArray = (arr, k) => {
  let rotatedArray = [...arr]  // Create a shallow copy of the array
  for (let i = 0; i < k; i++) {
    let lastElement = rotatedArray.pop()
    rotatedArray.unshift(lastElement)
  }
  return rotatedArray
}

