entity Multiplexer is 
  Port ( a,b,c,d: in  std_logic;
         sel: in  std_logic;
         y : out  std_logic);
end Multiplexer;

architecture Behavioral of Multiplexer is
    begin
    process(a,b,c,d,sel)
       begin
         if sel = '0' then
           y <= a;
         elsif sel = '1' then 
           y <= b;
         elsif sel = '2' then 
           y <= c; 
         elsif sel = '3' then
           y <= d;
         else
           y <= '0';
         end if;
    end process;
end Behavioral;

