int maxDepth(TreeNode* root) 
{ 
    if (root == NULL) 
        return 0; 
    else 
    { 
        // compute the depth of each subtree 
        int lDepth = maxDepth(root->left); 
        int rDepth = maxDepth(root->right); 

        // use the larger one 
        if (lDepth > rDepth) 
            return(lDepth + 1); 
        else return(rDepth + 1); 
    } 
}

