int attempts = 0;
while (true) {
 //Take input from user
 int num;
 int i = 0;
 cout << "Guess a 4 digit number: ";
 while (i < 4) {
  cin >> num;
  ans[i] = num;
  i++;
 }

 //Check input against random answer
 int correctplace = 0;
 int wrongplace = 0;
 for (i = 0; i < 4; i++) {
  int j = 0;
  while (j < 4) {
   if (ans[i] == ans[j] && i == j)
    correctplace++;
   else if (ans[i] == ans[j])
    wrongplace++;
   j++;
  }
 }

 attempts++;

 if (correctplace == 4) {
  cout << "You win in " << attempts << " attempts.";
  break;
 }
 else
  cout << "Wrong place: " << wrongplace << "    Correct place: " << correctplace << endl;
}
return 0;
}

