void reverse_sentence(char *word) 
{ 
    int k; 
    char *c, s[100]; 
    c = word; 
    k = strlen(word); 

    int i = k - 1, j = 0; 
    while (i >= 0) { 
        while (i >= 0 && c[i] != ' ') { 
           s[j++] = c[i--]; 
        } 
        s[j++] = ' '; 

        while (i >= 0 && c[i] == ' ') 
            i--; 
    } 

    s[j] = '\0'; 
    printf("%s\n", s); 
} 

