def factor_list(number):    
    factors = []

    i = 2
    while i * i <= number:
        if number % i:
            i += 1
        else:
            number //= i
            factors.append(i)
    if number > 1:
        factors.append(number)

    return factors

def boolean_search(list_of_numbers):
