def shortest_increasing_subarray(nums):
    res, curr = float('inf'), 0
    for i in range(len(nums)-1):
        if nums[i] < nums[i+1]: 
            curr += 1
        else:
            res = min(res, curr)
            curr = 0
    return max(res, curr) + 1

