def quadratic_equation(a,b,c):
   discriminant = pow(b,2)-4*a*c
   if(discriminant < 0):
      return "No real solutions"
   elif(discriminant == 0):
      return (-b + pow(discriminant, 0.5))/(2*a)
   else:
      return ((-b + pow(discriminant, 0.5))/(2*a), (-b - pow(discriminant, 0.5))/(2*a))

