//Reusable "push" and "pop" functions

void push(Stack *st, int val) {
    st->arr[st->top] = val;
    st->top++;
}

int pop(Stack *st) {
    return st->arr[--(st->top)];
}

//Functions for performing operations

int add(Stack *st) {
    int x = pop(st);
    int y = pop(st);
    return x + y;
}

int subtract(Stack *st) {
    int x = pop(st);
    int y = pop(st);
    return x - y;
}

int multiply(Stack *st) {
    int x = pop(st);
    int y = pop(st);
    return x * y;
}

int divide(Stack *st) {
    int x = pop(st);
    int y = pop(st);
    return x / y;
}

def prime_check(n):
    if n < 2: 
        return False
    if n == 2: 
        return True
    if not n & 1: 
        return False
    for x in range(3, int(n**0.5) + 1, 2):
        if n % x == 0:
            return False
    return True

