import re

#Function to validate an email
def is_valid_email(email):
    regex = '^\w+([\.-]?\w+)*@\w+([\.-]?\w+)*(\.\w{2,3})+$'
    if (re.search(regex, email)):  
        return True  
    else:  
        return False

#Test the function
if(is_valid_email("abc@gmail.com")): 
    print("Valid Email")  
else : 
    print("Invalid Email") 
